const token=$env.BALE_BOT_TOKEN; const sd=$getWorkflowStaticData('global'); let offset=sd.bale_offset||0;
let res; try{res=await this.helpers.httpRequest({method:'GET',url:'https://tapi.bale.ai/bot'+token+'/getUpdates'+(offset?('?offset='+offset):''),json:true});}catch(e){return [];}
const ups=(res&&res.result)||[]; if(!ups.length) return [];
let maxId=offset; const out=[];
for(const u of ups){ if(u.update_id>=maxId)maxId=u.update_id+1; const m=u.message; if(!m||!m.text)continue;
  const text=m.text.trim(); const chat=m.chat.id; const low=text.toLowerCase();
  if(low==='/exit'||low==='/stop'){ out.push({json:{type:'exit',chat}}); continue; }
  if(low==='/start'||low==='/help'){ out.push({json:{type:'help',chat}}); continue; }
  if(low==='/report'){ out.push({json:{type:'report',chat}}); continue; }
  if(low.startsWith('/'))continue;
  if(low.startsWith('fix:')){ out.push({json:{type:'fix',desc:text.slice(4).trim(),chat}}); continue; }
  if(low.startsWith('feature:')){ out.push({json:{type:'feature',desc:text.slice(8).trim(),chat}}); continue; }
  if(!/name:|repo:|idea:/i.test(text)) continue;  // پیام‌های معمولی/قدیمی نادیده گرفته شوند
  const g=(re)=>{const mm=text.match(re);return mm?mm[1].trim():'';};
  out.push({json:{type:'idea',name:g(/name:\s*(.+)/i),repo:g(/repo:\s*(\S+)/i),link:g(/link:\s*(\S+)/i),idea:g(/idea:\s*([\s\S]+)/i),chat}});
}
sd.bale_offset=maxId; return out;

const TK=$env.TRELLO_KEY,TT=$env.TRELLO_TOKEN,BOARD=$env.TRELLO_BOARD_ID;
const L={todo:$env.TRELLO_LIST_TODO,prog:$env.TRELLO_LIST_INPROGRESS,wait:$env.TRELLO_LIST_WAITING,review:$env.TRELLO_LIST_INREVIEW,owner:$env.TRELLO_LIST_OWNER};
const GHTOKEN=$env.GITHUB_TOKEN,OWNER_CHAT=$env.OWNER_CHAT,BALE=$env.BALE_BOT_TOKEN;
const CLAUDE_BRIDGE='http://host.docker.internal:8787/v1/messages';
const req=(o)=>this.helpers.httpRequest(o);
const tUrl=(p)=>'https://api.trello.com/1/'+p+(p.includes('?')?'&':'?')+'key='+TK+'&token='+TT;
const tGet=async(p)=>{try{return await req({method:'GET',url:tUrl(p),json:true});}catch(e){return [];}};
const tPost=async(p)=>req({method:'POST',url:tUrl(p),json:true});
const tPut=async(p)=>req({method:'PUT',url:tUrl(p),json:true});
const tDel=async(p)=>{try{return await req({method:'DELETE',url:tUrl(p),json:true});}catch(e){return null;}};
const bale=async(chat,text)=>{try{await req({method:'POST',url:'https://tapi.bale.ai/bot'+BALE+'/sendMessage',body:JSON.stringify({chat_id:chat,text}),headers:{'content-type':'application/json'},json:false});}catch(e){}};
const claude=async(prompt,mt)=>{const r=await req({method:'POST',url:CLAUDE_BRIDGE,body:JSON.stringify({model:'claude-opus-4-8',max_tokens:mt||3000,messages:[{role:'user',content:prompt}]}),headers:{'content-type':'application/json'},json:false});const j=typeof r==='string'?JSON.parse(r):r;return (j.content&&j.content[0]&&j.content[0].text)||'';};
const strip=(s)=>String(s||'').replace(/```json|```/g,'').trim();
const jparse=(t)=>{let s=strip(t);try{return JSON.parse(s);}catch(e){}let a=s.indexOf('{'),b=s.lastIndexOf('}');if(a>=0&&b>a){try{return JSON.parse(s.slice(a,b+1));}catch(e){}}let c=s.indexOf('['),d=s.lastIndexOf(']');if(c>=0&&d>c){try{return JSON.parse(s.slice(c,d+1));}catch(e){}}return null;};
const enc=(s)=>Buffer.from(s||'','utf8').toString('base64');
const normRepo=(u)=>String(u||'').trim().replace(/\.git$/,'').replace(/^https?:\/\/github\.com\//i,'').replace(/^github\.com\//i,'');
const gh=async(method,path,body,raw)=>{const r=await req({method,url:'https://api.github.com'+path,headers:{Authorization:'Bearer '+GHTOKEN,Accept:raw?'application/vnd.github.raw+json':'application/vnd.github+json','User-Agent':'n8n-bot'},body:body?JSON.stringify(body):undefined,json:false});if(raw)return typeof r==='string'?r:JSON.stringify(r);try{return typeof r==='string'?JSON.parse(r):r;}catch(e){return r;}};
const meta=(d)=>{d=String(d||'');const g=(re)=>{const m=d.match(re);return m?m[1].trim():'';};return{repo:normRepo(g(/repo:\s*(\S+)/)),project:g(/project:\s*(.+)/),ref:g(/ref:\s*(\S+)/)};};
const trackOf=(name)=>{const m=String(name||'').match(/^\[(backend|frontend|mobile)\]/);return m?m[1]:'backend';};
const CI_YML="name: CI\non:\n  pull_request:\n    branches: [ develop ]\njobs:\n  backend:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-python@v5\n        with: { python-version: '3.12' }\n      - name: backend tests\n        run: |\n          if [ -d backend ]; then\n            cd backend\n            pip install -r requirements.txt 2>/dev/null || pip install django djangorestframework pytest pytest-django\n            python -m pytest -q\n          else echo \"no backend yet\"; fi\n  frontend:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-node@v4\n        with: { node-version: '20' }\n      - name: frontend tests\n        run: |\n          if [ -f frontend/package.json ]; then\n            cd frontend\n            npm ci || npm install\n            npm test -- --watch=false --browsers=ChromeHeadless\n          else echo \"no frontend yet\"; fi\n  mobile:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-java@v4\n        with: { distribution: 'temurin', java-version: '17' }\n      - name: mobile tests\n        run: |\n          if [ -f mobile/gradlew ]; then\n            cd mobile\n            chmod +x gradlew && ./gradlew test\n          else echo \"no mobile yet\"; fi\n";

const STACK={"backend": "نقش: Backend Developer. استک: Python + Django + Django REST Framework با معماری تمیز. کل کد زیر پوشه‌ی backend/ و یک پکیج کامل و قابل‌اجرا (requirements.txt شامل django/djangorestframework/pytest/pytest-django، settings، manage.py در صورت نیاز). حداقل ۳ unit test با pytest در backend/ بنویس.", "frontend": "نقش: Frontend Developer. استک: Angular (standalone components، TypeScript، RxJS). کل کد زیر پوشه‌ی frontend/ و package.json با اسکریپت test. سرویس HTTP بر اساس مستندات API. حداقل ۳ unit test (jasmine/karma یا jest) بنویس.", "mobile": "نقش: Mobile Developer. استک: Kotlin Multiplatform + Compose Multiplatform (Android/iOS). کل کد زیر پوشه‌ی mobile/ با Gradle. لایه شبکه با Ktor بر اساس مستندات API. حداقل ۳ unit test (kotlin.test) بنویس."};
const readStack=async(t)=>{ try{ const s=await req({method:'GET',url:'http://host.docker.internal:8787/stack/'+t,json:false}); const v=String(s||'').trim(); return v||(STACK&&STACK[t])||''; }catch(e){ return (STACK&&STACK[t])||''; } };
const readRole=async(role)=>{ try{ const s=await req({method:'GET',url:'http://host.docker.internal:8787/role/'+role,json:false}); return String(s||'').trim(); }catch(e){ return ''; } };
const genCI=async()=>{ try{ const sb=await readStack('backend'),sf=await readStack('frontend'),sm=await readStack('mobile'); const raw=await claude('بر اساس این استک‌ها یک فایل GitHub Actions workflow (YAML) بساز که روی pull_request به شاخه‌ی develop اجرا شود و برای هر بخش موجود، پروژه را هم build و هم test کند. سه job جدا به نام‌های backend، frontend، mobile. هر job اول باید چک کند پوشه‌اش (backend/ یا frontend/ یا mobile/) وجود دارد و فقط در آن صورت build/test کند؛ اگر نبود فقط echo بزند و سبز رد شود. setup و کش مناسب هر زبان را بگذار. فقط YAML خام برگردان بدون توضیح و بدون بک‌تیک.\n\n[backend]\n'+sb+'\n\n[frontend]\n'+sf+'\n\n[mobile]\n'+sm,3000); let y=String(raw||'').replace(/```yaml|```yml|```/g,'').trim(); return (y.includes('jobs:')&&y.includes('pull_request'))?y:''; }catch(e){ return ''; } };
const mkWf=(track,steps)=>['name: CI '+track,'on:','  pull_request:','    branches: [ develop ]','    paths:',"      - '"+track+"/**'",'  workflow_dispatch:','jobs:','  '+track+':','    runs-on: ubuntu-latest','    steps:','      - uses: actions/checkout@v4'].concat(steps).join('\n')+'\n';
const ciBackend=(s)=>{ s=String(s||'').replace(/<!--[\s\S]*?-->/g,'').toLowerCase();
  if(/(node|express|nest|npm|javascript|typescript)/.test(s)&&!/(python|django|flask|fastapi)/.test(s)) return mkWf('backend',['      - uses: actions/setup-node@v4',"        with: { node-version: '20' }",'      - name: install & test','        run: |','          cd backend','          npm ci || npm install','          CI=true npm test']);
  if(/(golang|\bgo\b)/.test(s)) return mkWf('backend',['      - uses: actions/setup-go@v5',"        with: { go-version: '1.22' }",'      - name: test','        run: |','          cd backend','          go test ./...']);
  if(/(spring|maven|\bjava\b)/.test(s)&&!/kotlin/.test(s)) return mkWf('backend',['      - uses: actions/setup-java@v4',"        with: { distribution: 'temurin', java-version: '17' }",'      - name: test','        run: |','          cd backend','          ./mvnw -q test || mvn -q test']);
  return mkWf('backend',['      - uses: actions/setup-python@v5',"        with: { python-version: '3.12' }",'      - name: install & test','        run: |','          cd backend','          pip install -r requirements.txt 2>/dev/null || pip install django djangorestframework pytest pytest-django','          python -m pytest -q']);
};
const ciFrontend=(s)=>{ s=String(s||'').replace(/<!--[\s\S]*?-->/g,'').toLowerCase();
  if(/(angular|react|vue|svelte|next|vite|npm|package\.json|jest|jasmine|karma|typescript|\bnode\b)/.test(s)) return mkWf('frontend',['      - uses: actions/setup-node@v4',"        with: { node-version: '20' }",'      - name: install & test','        run: |','          cd frontend','          npm ci || npm install','          CI=true npm test']);
  return mkWf('frontend',['      - name: static html/css check','        run: |','          cd frontend','          n=$(find . -name "*.html" | wc -l)','          if [ "$n" -eq 0 ]; then echo "no html files found"; exit 1; fi','          for f in $(find . -name "*.html"); do grep -qi "<html" "$f" || echo "::warning::$f has no <html> tag"; done','          echo "static frontend ok ($n html files)"']);
};
const ciMobile=(s)=>{ s=String(s||'').replace(/<!--[\s\S]*?-->/g,'').toLowerCase();
  if(/(flutter|dart)/.test(s)) return mkWf('mobile',['      - uses: subosito/flutter-action@v2',"        with: { channel: 'stable' }",'      - name: test','        run: |','          cd mobile','          flutter pub get','          flutter test']);
  if(/(react native|react-native)/.test(s)) return mkWf('mobile',['      - uses: actions/setup-node@v4',"        with: { node-version: '20' }",'      - name: test','        run: |','          cd mobile','          npm ci || npm install','          CI=true npm test']);
  return mkWf('mobile',['      - uses: actions/setup-java@v4',"        with: { distribution: 'temurin', java-version: '17' }",'      - name: test','        run: |','          cd mobile','          chmod +x gradlew','          ./gradlew test']);
};
const bootstrap=async(repo)=>{ const [o,r]=repo.split('/');
  let okMain=true; try{await gh('GET','/repos/'+o+'/'+r+'/git/ref/heads/main');}catch(e){okMain=false;}
  if(!okMain){ await gh('PUT','/repos/'+o+'/'+r+'/contents/README.md',{message:'init',content:enc('# '+r+'\n')}); }
  const sb=await readStack('backend'),sf=await readStack('frontend'),sm=await readStack('mobile');
  const wfFiles={'.github/workflows/backend.yml':ciBackend(sb),'.github/workflows/frontend.yml':ciFrontend(sf),'.github/workflows/mobile.yml':ciMobile(sm)};
  const scaffold={'backend/README.md':'# Backend\n','frontend/README.md':'# Frontend\n','mobile/README.md':'# Mobile\n','docs/api/API.md':'# API Documentation\n'};
  let okDev=true; try{await gh('GET','/repos/'+o+'/'+r+'/git/ref/heads/develop');}catch(e){okDev=false;}
  if(!okDev){ try{ const ref=await gh('GET','/repos/'+o+'/'+r+'/git/ref/heads/main'); await gh('POST','/repos/'+o+'/'+r+'/git/refs',{ref:'refs/heads/develop',sha:ref.object.sha}); }catch(e2){} }
  const getSha=async(branch,p)=>{ try{ return (await gh('GET','/repos/'+o+'/'+r+'/contents/'+p+'?ref='+branch)).sha; }catch(e){ return null; } };
  const put=async(branch,p,content,overwrite)=>{ const sha=await getSha(branch,p); if(sha&&!overwrite) return null; const body={message:'chore: ci '+p,content:enc(content),branch}; if(sha)body.sha=sha; try{ await gh('PUT','/repos/'+o+'/'+r+'/contents/'+p,body); return null; }catch(e){ return (e&&e.message)||String(e); } };
  let wfErr='';
  for(const br of ['main','develop']){ for(const p of Object.keys(wfFiles)){ const er=await put(br,p,wfFiles[p],true); if(er&&!wfErr)wfErr=p+' ('+br+'): '+er; } for(const p of Object.keys(scaffold)){ await put(br,p,scaffold[p],false); } }
  if(wfErr){ await bale(OWNER_CHAT,'⚠️ ساخت فایل‌های CI ناموفق بود.\nعلت محتمل: توکن گیت‌هاب اسکوپ workflow ندارد. یک Classic Token با تیکِ repo + workflow بساز و در secrets.env بگذار.\n\nخطا: '+String(wfErr).slice(0,300)); }
  for(const br of ['main','develop']){ const sha=await getSha(br,'.github/workflows/ci.yml'); if(sha){ try{ await gh('DELETE','/repos/'+o+'/'+r+'/contents/.github/workflows/ci.yml',{message:'chore: remove monolith ci.yml',sha,branch:br}); }catch(e){} } }
};
const findMeta=async()=>{ for(const k of ['todo','prog','review','wait']){ const cs=await tGet('lists/'+L[k]+'/cards?fields=desc'); for(const c of cs){ const mm=meta(c.desc); if(mm.repo)return mm; } } return null; };
const HELP_TEXT='🤖 راهنمای استارتاپ خودکار\n\nشروع پروژه‌ی جدید (یک بلوک بفرست):\nname: نام پروژه\nrepo: لینک ریپو گیت‌هاب\nidea: شرح چیزی که می‌خوای ساخته شود\n(link اختیاری)\n\nدستورها:\n• fix: شرح باگ — افزودن تسک رفع باگ به پروژه‌ی فعال\n• feature: شرح قابلیت — افزودن قابلیت جدید\n• /exit — خروج اضطراری و توقف کامل پروژه‌ی فعال\n• /report — دریافت گزارش لحظه‌ای به ازای هر تسک\n• /help — نمایش همین راهنما\n\nنکته: هر زمان فقط یک پروژه فعال است؛ گزارش روزانه به ازای هر تسک فرستاده می‌شود.';
const poRole=(await readRole('product-owner'))||'تو Product Owner هستی.';
const out=[];
for(const it of items){ const m=it.json; const chat=m.chat||OWNER_CHAT;
  if(m.type==='help'){ await bale(chat,HELP_TEXT); out.push({json:{help:1}}); continue; }
  if(m.type==='exit'){ let cleared=0; for(const k of Object.keys(L)){ const cs=await tGet('lists/'+L[k]+'/cards?fields=id'); cleared+=cs.length; for(const cc of cs){ await tDel('cards/'+cc.id); } } await bale(chat,'🛑 خروج اضطراری انجام شد. '+cleared+' تسک متوقف و از برد پاک شد. برای شروع دوباره یک ایده‌ی جدید بفرست (یا /help).'); out.push({json:{exit:cleared}}); continue; }
  if(m.type==='report'){
    const SLABEL={todo:'در صف (To Do)',prog:'در حال انجام',wait:'منتظر API',review:'در حال ریویو',owner:'تمام‌شده / merge'};
    const sendLong=async(ch,text)=>{ if(!text)return; const max=3500; for(let i=0;i<text.length;i+=max){ await bale(ch,text.slice(i,i+max)); } };
    let blocks=[]; let total=0;
    for(const k of Object.keys(L)){ const cs=await tGet('lists/'+L[k]+'/cards?fields=name,desc'); for(const cc of cs){ total++;
      let comments=[]; try{ const acts=await tGet('cards/'+cc.id+'/actions?filter=commentCard&limit=30'); comments=(acts||[]).map(a=>a&&a.data&&a.data.text).filter(Boolean).reverse(); }catch(e){}
      const bugs=comments.filter(t=>t.indexOf('🔴')>=0).length; const fixes=comments.filter(t=>t.indexOf('🛠️')>=0).length;
      const dsc=String(cc.desc||'').split('\n---')[0].trim().slice(0,300);
      blocks.push('### '+cc.name+'\nوضعیت: '+(SLABEL[k]||k)+' | باگ‌ها: '+bugs+' | فیکس‌ها: '+fixes+'\nشرح: '+(dsc||'-')+'\nسابقه:\n'+(comments.length?comments.map(t=>'- '+t.slice(0,300)).join('\n'):'- (بدون سابقه)')); } }
    if(!total){ await bale(chat,'📊 گزارش: بردی خالی است.'); out.push({json:{report:0}}); continue; }
    let rep=''; try{ rep=await claude('بر اساس داده‌های زیر یک گزارش فارسی «به ازای هر تسک» بنویس. برای هر تسک با تیتر مشخص: ۱) موضوع تسک ۲) وضعیت و میزان پیشرفت ۳) چه باگ‌هایی داشته و چطور فیکس شده. خوانا و خلاصه؛ اگر تسکی بدون باگ بوده همان را بگو.\n\n'+blocks.join('\n\n'),3500); }catch(e){}
    if(!rep) rep=blocks.join('\n\n');
    await sendLong(chat,'📊 گزارش به ازای هر تسک:\n\n'+rep); out.push({json:{report:total}}); continue;
  }
  if(m.type==='fix'||m.type==='feature'){
    const mm=await findMeta();
    if(!mm){ await bale(chat,'⚠️ پروژه‌ی فعالی نیست. اول یک ایده‌ی کامل (name/repo/idea) بفرست.'); out.push({json:{skip:1}}); continue; }
    const kind=m.type==='fix'?'رفع باگ':'قابلیت جدید';
    const t=jparse(await claude(poRole+'\n\nاین یک درخواست '+kind+' است. یک JSON بده با کلیدهای title و desc و track(backend/frontend/mobile) و complexity(boilerplate/medium/complex). فقط JSON. درخواست: '+m.desc,1500))||{title:(m.desc||'').slice(0,50),desc:m.desc,track:'backend',complexity:'medium'};
    const name='['+(t.track||'backend')+']['+(t.complexity||'medium')+']['+m.type+'] '+t.title;
    const desc=(t.desc||'')+'\n\n---\nrepo: '+mm.repo+'\nproject: '+mm.project+(mm.ref?'\nref: '+mm.ref:'');
    await tPost('cards?idList='+L.todo+'&name='+encodeURIComponent(name)+'&desc='+encodeURIComponent(desc));
    await bale(chat,'✅ '+kind+' اضافه شد:\n• '+name); out.push({json:{added:name}}); continue;
  }
  // === idea ===
  if(!m.name||!m.repo||!m.idea){ await bale(chat,'⚠️ فرمت ناقص. لازم:\nname: نام پروژه\nrepo: لینک ریپو\nidea: شرح\n(link اختیاری)'); out.push({json:{bad:1}}); continue; }
  let active=0; for(const k of ['todo','prog','review','wait']){ const cs=await tGet('lists/'+L[k]+'/cards?fields=id'); active+=cs.length; }
  if(active>0){ await bale(chat,'⛔ یک پروژه در جریان است ('+active+' تسک فعال). تا تمام نشود ایده‌ی جدید نمی‌گیرم. برای رفع/افزودن از fix: یا feature: استفاده کن.'); out.push({json:{blocked:1}}); continue; }
  // clear board (همه‌ی ستون‌ها)
  for(const k of Object.keys(L)){ const cs=await tGet('lists/'+L[k]+'/cards?fields=id'); for(const c of cs){ await tDel('cards/'+c.id); } }
  const repo=normRepo(m.repo);
  const v=jparse(await claude('آیا این یک ایده‌ی واقعی برای ساخت نرم‌افزار است؟ یک JSON بده با کلیدهای is_valid (boolean) و reason (string). فقط JSON. پیام: '+m.idea,500))||{is_valid:true};
  if(v.is_valid===false){ await bale(chat,'⚠️ ایده‌ی معتبر نیست: '+(v.reason||'')); out.push({json:{invalid:1}}); continue; }
  await bale(chat,'⏳ پروژه «'+m.name+'» در حال آماده‌سازی ریپو و تسک‌ها...');
  try{ await bootstrap(repo); }catch(e){ await bale(chat,'⚠️ خطا در آماده‌سازی ریپو: '+e.message+' — مطمئن شو ریپو وجود دارد و توکن دسترسی دارد.'); out.push({json:{repoErr:1}}); continue; }
  await bale(chat,'🛠️ CI متناسب با استک‌ها روی شاخه‌ی develop راه‌اندازی شد (build + test). هر PR قبل از merge باید CI سبز بگیرد.');
  let rawT=''; try{ rawT=await claude(poRole+'\n\nاین ایده را به تسک‌های اتمیک بشکن. '+(m.link?('یک مرجع هم لحاظ شود: '+m.link+'. '):'')+'نام پروژه: '+m.name+'. فقط آن بخش‌هایی که در ایده لازم‌اند (backend/frontend/mobile). خروجی فقط JSON با کلید tasks که آرایه‌ای از اشیاء با کلیدهای title و desc و track و complexity است. track یکی از backend/frontend/mobile. complexity یکی از boilerplate/medium/complex. برای هر بخش حداقل یک تسک تست هم بگذار. فقط JSON بدون متن اضافه. ایده: '+m.idea,4000); }catch(e){ rawT='ERR:'+e.message; }
  const parsedT=jparse(rawT); const tasks=(parsedT&&parsedT.tasks)||[];
  if(!tasks.length){ await bale(chat,'⚠️ تسکی تولید نشد. پاسخ مدل:\n'+String(rawT).slice(0,500)); out.push({json:{notasks:1}}); continue; }
  const hasBackend=tasks.some(t=>(t.track||'backend').toLowerCase()==='backend');
  const names=[];
  for(const t of tasks){ const tr=(t.track||'backend').toLowerCase();
