    const desc=(t.desc||'')+'\n\n---\nrepo: '+repo+'\nproject: '+m.name+(m.link?'\nref: '+m.link:'');
    await tPost('cards?idList='+list+'&name='+encodeURIComponent(name)+'&desc='+encodeURIComponent(desc)); names.push('• '+name);
